// Idempotency Check v2.0 - Context Preservation Pattern
const input = $input.first().json;
const body = input.body || input;

// Validación de input requerido (SEC02 - PRE validation)
const required = ['provider_id', 'service_id', 'start_time'];
for (const field of required) {
  if (!body[field]) {
    return [{ json: { _error: true, _error_message: `Missing required field: ${field}` } }];
  }
}

// Generar idempotency_key determinístico
const idempotencyKey = `booking_${body.provider_id}_${body.service_id}_${body.start_time}_${body.customer_id || body.chat_id || 'anonymous'}`;

// Sanitizar string (SEC05)
const sanitizedKey = idempotencyKey.replace(/[^a-zA-Z0-9_:-]/g, '_').substring(0, 255);

// Construir contexto único que viajará por todo el workflow
const ctx = {
  provider_id: parseInt(body.provider_id, 10),
  service_id: parseInt(body.service_id, 10),
  start_time: body.start_time,
  end_time: body.end_time || null,
  customer_id: body.customer_id || null,
  chat_id: body.chat_id || null,
  user_id: body.user_id || null,
  duration_minutes: parseInt(body.duration_minutes || 60, 10),
  event_title: body.event_title || null,
  idempotency_key: sanitizedKey,
  _idempotency: {
    key: sanitizedKey,
    created_at: new Date().toISOString()
  },
  _meta: {
    source: 'WF2_BOOKING_ORCHESTRATOR',
    version: '2.0.0',
    started_at: new Date().toISOString()
  }
};

return [{ json: { ctx } }];

// DUPLICATE BRANCH - Return existing booking
const existing = $input.first().json[0] || $input.first().json;
const ctx = $input.first().json.ctx || {};

ctx._idempotency.is_duplicate = true;
ctx._idempotency.existing_booking_id = existing.id;

return [{
  json: {
    ctx,
    success: true,
    error_code: null,
    error_message: null,
    data: {
      booking_id: existing.id,
      status: existing.status,
      gcal_event_id: existing.gcal_event_id,
      is_duplicate: true,
      message: 'Booking already exists (idempotent retry)'
    },
    _meta: {
      source: 'WF2_BOOKING_ORCHESTRATOR',
      timestamp: new Date().toISOString(),
      version: '2.0.0',
      idempotency: 'duplicate'
    }
  }
}];

// MERGE CONTEXT - After Is Duplicate? (false branch)
// Get ctx from Generate Idempotency Key node
const ctx = $("Generate Idempotency Key").first()?.json?.ctx || {};
ctx._idempotency.is_duplicate = false;
return [{ json: { ctx } }];

// NOT AVAILABLE BRANCH
const ctx = $input.first().json.ctx;
ctx._meta.failed_at = 'Check Availability';

return [{
  json: {
    ctx,
    success: false,
    error_code: 'NO_AVAILABILITY',
    error_message: 'No availability found for requested time slot',
    data: null,
    _meta: {
      source: 'WF2_BOOKING_ORCHESTRATOR',
      timestamp: new Date().toISOString(),
      version: '2.0.0'
    }
  }
}];

// MERGE CONTEXT - After Is Available? (true branch)
// Get ctx from Generate Idempotency Key node and merge with availability response
const ctx = $("Generate Idempotency Key").first()?.json?.ctx || {};
const availResponse = $input.first().json;

// Preserve availability data in context
ctx._availability = {
  checked: true,
  available: true,
  slots: availResponse.data?.slots || [],
  timestamp: new Date().toISOString()
};

return [{ json: { ctx } }];

// CIRCUIT BREAKER OPEN
const ctx = $input.first().json.ctx;
ctx._meta.failed_at = 'Circuit Breaker';

return [{
  json: {
    ctx,
    success: false,
    error_code: 'CIRCUIT_BREAKER_OPEN',
    error_message: 'Google Calendar service is temporarily unavailable',
    data: null,
    _meta: {
      source: 'WF2_BOOKING_ORCHESTRATOR',
      timestamp: new Date().toISOString(),
      version: '2.0.0'
    }
  }
}];

// Prepare DB Values for Create Booking
// Extract values from GCal Event and context
const gcalEvent = $('Create GCal Event').first()?.json || {};
const ctx = $('Generate Idempotency Key').first()?.json?.ctx || {};

// GCal event ID is in data.id
const gcalEventId = gcalEvent.id || gcalEvent.data?.id || '';

// User ID validation - use default if user_id not provided
// IMPORTANT: Do NOT use chat_id as user_id - they are different entities
// Default to TELEGRAM_ID (5391760292) which is a known valid user
const DEFAULT_USER_ID = 5391760292;
let userId = DEFAULT_USER_ID;

if (ctx.user_id && ctx.user_id > 0) {
  userId = ctx.user_id;
}
// Note: We do NOT use ctx.chat_id here as it's not a valid user_id

// Calculate end_time (start + 1 hour)
const startTime = new Date(ctx.start_time);
const endTime = new Date(startTime.getTime() + 60 * 60 * 1000);

return [{
  json: {
    ctx,
    gcal_event_id: gcalEventId,
    user_id: userId,
    end_time: endTime.toISOString()
  }
}];

// Standard Contract Output - Booking Success v2.0
const db = $('Create DB Booking').first()?.json || {};
const ctx = $('Generate Idempotency Key').first()?.json?.ctx || {};

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      booking_id: db.id,
      idempotency_key: ctx.idempotency_key,
      provider_id: ctx.provider_id,
      service_id: ctx.service_id,
      start_time: ctx.start_time,
      status: 'CONFIRMED',
      is_duplicate: ctx._idempotency?.is_duplicate || false
    },
    _meta: {
      source: 'WF2_BOOKING_ORCHESTRATOR',
      timestamp: new Date().toISOString(),
      version: '2.0.0'
    }
  }
}];
